@SuppressWarnings("unchecked")
    public T getExtension(String name, boolean wrap) {
        checkDestroyed();
        if (StringUtils.isEmpty(name)) {
            throw new IllegalArgumentException("Extension name == null");
        }
        if ("true".equals(name)) {
            return getDefaultExtension();
        }
        String cacheKey = name;
        if (!wrap) {
            cacheKey += "_origin";
        }
        final Holder<Object> holder = getOrCreateHolder(cacheKey);
        Object instance = holder.get();
        if (instance == null) {
            synchronized (holder) {
                instance = holder.get();
                if (instance == null) {
                    instance = createExtension(name, wrap);
                    holder.set(instance);
                }
            }
        }
        return (T) instance;
    }

@Override
    public T read(JsonReader in) throws IOException {
      if (in.peek() == JsonToken.NULL) {
        in.nextNull();
        return null;
      }

      A accumulator = createAccumulator();
      Map<String, BoundField> deserializedFields = fieldsData.deserializedFields;

      try {
        in.beginObject();
        while (in.hasNext()) {
          String name = in.nextName();
          BoundField field = deserializedFields.get(name);
          if (field == null) {
            in.skipValue();
          } else {
            readField(accumulator, in, field);
          }
        }
      } catch (IllegalStateException e) {
        throw new JsonSyntaxException(e);
      } catch (IllegalAccessException e) {
        throw ReflectionHelper.createExceptionForUnexpectedIllegalAccess(e);
      }
      in.endObject();
      return finalize(accumulator);
    }

public static boolean isEmpty(final Object object) {
    if (object == null) {
        return true;
    }
    if (object instanceof CharSequence) {
        return ((CharSequence) object).length() == 0;
    }
    if (isArray(object)) {
        return Array.getLength(object) == 0;
    }
    if (object instanceof Collection<?>) {
        return ((Collection<?>) object).isEmpty();
    }
    if (object instanceof Map<?, ?>) {
        return ((Map<?, ?>) object).isEmpty();
    }
    if (object instanceof Optional<?>) {
        // TODO Java 11 Use Optional#isEmpty()
        return !((Optional<?>) object).isPresent();
    }
    return false;
}

static ChronoUnit toChronoUnit(final TimeUnit timeUnit) {
    // TODO when using Java >= 9: Use TimeUnit.toChronoUnit().
    switch (Objects.requireNonNull(timeUnit)) {
    case NANOSECONDS:
        return ChronoUnit.NANOS;
    case MICROSECONDS:
        return ChronoUnit.MICROS;
    case MILLISECONDS:
        return ChronoUnit.MILLIS;
    case SECONDS:
        return ChronoUnit.SECONDS;
    case MINUTES:
        return ChronoUnit.MINUTES;
    case HOURS:
        return ChronoUnit.HOURS;
    case DAYS:
        return ChronoUnit.DAYS;
    default:
        throw new IllegalArgumentException(timeUnit.toString());
    }
}

Range(final T element1, final T element2, final Comparator<T> comp) {
    Objects.requireNonNull(element1, "element1");
    Objects.requireNonNull(element2, "element2");
    if (comp == null) {
        this.comparator = ComparableComparator.INSTANCE;
    } else {
        this.comparator = comp;
    }
    if (this.comparator.compare(element1, element2) < 1) {
        this.minimum = element1;
        this.maximum = element2;
    } else {
        this.minimum = element2;
        this.maximum = element1;
    }
    this.hashCode = hash(minimum, maximum);
}

public void start() {
    switch (WORKER_STATE_UPDATER.get(this)) {
        case WORKER_STATE_INIT:
            if (WORKER_STATE_UPDATER.compareAndSet(this, WORKER_STATE_INIT, WORKER_STATE_STARTED)) {
                workerThread.start();
            }
            break;
        case WORKER_STATE_STARTED:
            break;
        case WORKER_STATE_SHUTDOWN:
            throw new IllegalStateException("cannot be started once stopped");
        default:
            throw new Error("Invalid WorkerState");
    }

    // Wait until the startTime is initialized by the worker.
    while (startTime == 0) {
        try {
            startTimeInitialized.await();
        } catch (InterruptedException ignore) {
            // Ignore - it will be ready very soon.
        }
    }
}

