public void visitLdcInsn(final String value) {
    final int CONSTANT_STRING_TAG = 8;

    lastBytecodeOffset = code.length;
    // Add the instruction to the bytecode of the method.
    Symbol constantSymbol = symbolTable.addConstantUtf8Reference(CONSTANT_STRING_TAG, value);
    int constantIndex = constantSymbol.index;
    if (constantIndex >= 256) {
        code.put12(Constants.LDC_W, constantIndex);
    } else {
        code.put11(Opcodes.LDC, constantIndex);
    }
    // If needed, update the maximum stack size and number of locals, and stack map frames.
    if (currentBasicBlock != null) {
        currentBasicBlock.frame.execute(Opcodes.LDC, 0, constantSymbol, symbolTable);
    }
}

private void visitSwitchInsn(final Label dflt, final Label[] labels) {
    if (currentBasicBlock != null) {
        currentBasicBlock.frame.execute(Opcodes.LOOKUPSWITCH, 0, null, null);
        // Add all the labels as successors of the current basic block.
        addSuccessorToCurrentBasicBlock(dflt);
        dflt.getCanonicalInstance().flags |= Label.FLAG_JUMP_TARGET;
        for (int i = 0; i < labels.length; i++) {
            Label label = labels[i];
            addSuccessorToCurrentBasicBlock(label);
            label.getCanonicalInstance().flags |= Label.FLAG_JUMP_TARGET;
        }
        // End the current basic block.
        endCurrentBasicBlockWithNoSuccessor();
    }
}

String convert(CaseFormat format, String s) {
  // deal with camel conversion
  StringBuilder out = null;
  int i = 0;
  int j = -1;
  while ((j = wordBoundary.indexIn(s, ++j)) != -1) {
    if (i == 0) {
      // include some extra space for separators
      out = new StringBuilder(s.length() + 4 * format.wordSeparator.length());
      out.append(format.normalizeFirstWord(s.substring(i, j)));
    } else {
      requireNonNull(out).append(format.normalizeWord(s.substring(i, j)));
    }
    out.append(format.wordSeparator);
    i = j + wordSeparator.length();
  }
  return (i == 0)
      ? format.normalizeFirstWord(s)
      : requireNonNull(out).append(format.normalizeWord(s.substring(i))).toString();
}

public static int log2(int x, RoundingMode mode) {
  checkPositive("x", x);
  switch (mode) {
    case UNNECESSARY:
      checkRoundingUnnecessary(isPowerOfTwo(x));
    // fall through
    case DOWN:
    case FLOOR:
      return (Integer.SIZE - 1) - Integer.numberOfLeadingZeros(x);

    case UP:
    case CEILING:
      return Integer.SIZE - Integer.numberOfLeadingZeros(x - 1);

    case HALF_DOWN:
    case HALF_UP:
    case HALF_EVEN:
      // Since sqrt(2) is irrational, log2(x) - logFloor cannot be exactly 0.5
      int leadingZeros = Integer.numberOfLeadingZeros(x);
      int cmp = MAX_POWER_OF_SQRT2_UNSIGNED >>> leadingZeros;
      // floor(2^(logFloor + 0.5))
      int logFloor = (Integer.SIZE - 1) - leadingZeros;
      return logFloor + lessThanBranchFree(cmp, x);
  }
  throw new AssertionError();
}

public SingleRouterChain<T> getSingleChain(URL url, BitList<Invoker<T>> availableInvokers, Invocation invocation) {
    // If current is in:
    // 1. `setInvokers` is in progress
    // 2. Most of the invocation should use backup chain => currentChain == backupChain
    // 3. Main chain has been update success => notifyingInvokers.get() != null
    //     If `availableInvokers` is created from origin invokers => use backup chain
    //     If `availableInvokers` is created from newly invokers  => use main chain
    BitList<Invoker<T>> notifying = notifyingInvokers.get();
    if (notifying != null
            && currentChain == backupChain
            && availableInvokers.getOriginList() == notifying.getOriginList()) {
        return mainChain;
    }
    return currentChain;
}

static String boxed(String type) {
    String boxed = type;
    switch (type) {
        case "int":
            boxed = "Integer";
            break;
        case "long":
            boxed = "Long";
            break;
        case "float":
            boxed = "Float";
            break;
        case "double":
            boxed = "Double";
            break;
        case "boolean":
            boxed = "Boolean";
            break;
        case "char":
            boxed = "Character";
            break;
        case "byte":
            boxed = "Byte";
            break;
        case "short":
            boxed = "Short";
            break;
        default:
    }
    return boxed;
}
